precision mediump float;
uniform sampler2D u_texture;
uniform float u_time;
uniform vec2 u_resolution;
varying vec2 v_uv;

void main()
{
    vec3 color = texture2D(u_texture, v_uv).rgb;

    float num_bands = 4.0;
    float step = 1.0 / num_bands;

    vec3 finalColor = vec3(0.0);

    for (int i = 0; i < 3; i++)
    {
        float sum = 0.0;
        for (int j = 0; j < int(num_bands); j++)
        {
            float sample = texture2D(u_texture, v_uv + vec2(float(j) * step, 0.0)).r;
            sum += sample;
        }
        float average = sum / num_bands;

        vec3 bandColor;
        if (i == 0)
        {
            bandColor = vec3(average, 0.0, 0.0);
        }
        else if (i == 1)
        {
            bandColor = vec3(0.0, average, 0.0);
        }
        else
        {
            bandColor = vec3(0.0, 0.0, average);
        }

        finalColor += bandColor;
    }

    gl_FragColor = vec4(clamp(finalColor, 0.0, 1.0), 1.0);
}

