response:
precision mediump float;
uniform sampler2D u_texture;
uniform float u_time;
uniform vec2 u_resolution;
varying vec2 v_uv;

void main()
{
    float num_bands = 4.0;
    float step = 1.0 / num_bands;

    vec3 color = texture2D(u_texture, v_uv).rgb;

    float r = mod(color.r * num_bands, 1.0) / num_bands;
    float g = mod(color.g * num_bands, 1.0) / num_bands;
    float b = mod(color.b * num_bands, 1.0) / num_bands;

    vec3 posterized_color = vec3(r, g, b);

    gl_FragColor = vec4(clamp(posterized_color, 0.0, 1.0), 1.0);
}
}
